use std::collections::HashMap;
use std::hash::Hash;

pub struct Memoize<F, K, V>
where
    K: Hash + Eq + Clone,
    V: Clone,
{
    func: F,
    cache: HashMap<K, V>,
}

impl<F, K, V> Memoize<F, K, V>
where
    K: Hash + Eq + Clone,
    V: Clone,
    F: Fn(K) -> V,
{
    pub fn new(func: F) -> Self {
        Memoize {
            func,
            cache: HashMap::new(),
        }
    }
}
